/**
 * OAuth broker — handles PKCE and token exchange server-side.
 *
 * Two operation modes:
 *   Managed  – set GOOGLE_CLIENT_ID + GOOGLE_CLIENT_SECRET env vars
 *   BYOK     – caller passes client_id + client_secret as query params
 *
 * Two delivery modes:
 *   web_message (default) – popup postMessages tokens back to opener
 *   redirect              – redirects to original URI with tokens in URL hash
 */

import crypto from "crypto"
import express, { type Request, type Response } from "express"

const app = express()

// ─── Constants ─────────────────────────────────────────────────────────────────

const GOOGLE_AUTH_URL = "https://accounts.google.com/o/oauth2/v2/auth"
const GOOGLE_TOKEN_URL = "https://oauth2.googleapis.com/token"
const SESSION_TTL_MS = 5 * 60 * 1_000 // 5 minutes

// ─── Session store ─────────────────────────────────────────────────────────────

interface PKCESession {
  codeVerifier: string
  /** Original state value generated by the browser client */
  clientState: string
  clientId: string
  clientSecret: string
  /** The redirect_uri we registered with Google for the token exchange */
  callbackRedirectUri: string
  deliveryMode: "web_message" | "redirect"
  /** Where to redirect after redirect-mode token exchange */
  originalRedirectUri: string
  createdAt: number
}

const sessions = new Map<string, PKCESession>()

// Prune expired sessions every minute to prevent unbounded memory growth
setInterval(() => {
  const cutoff = Date.now() - SESSION_TTL_MS
  for (const [id, s] of sessions) {
    if (s.createdAt < cutoff) sessions.delete(id)
  }
}, 60_000).unref()

// ─── PKCE helpers ──────────────────────────────────────────────────────────────

function generateCodeVerifier(): string {
  // 96 random bytes → 128-char base64url string (within 43–128 range)
  return crypto.randomBytes(96).toString("base64url")
}

function generateCodeChallenge(verifier: string): string {
  return crypto.createHash("sha256").update(verifier).digest("base64url")
}

function generateSessionId(): string {
  return crypto.randomBytes(16).toString("hex")
}

// ─── Routes ────────────────────────────────────────────────────────────────────

app.get("/~oauth/initiate", (req: Request, res: Response) => {
  const {
    provider,
    state,
    redirect_uri,
    client_id,
    client_secret,
    mode = "web_message",
    ...extraParams
  } = req.query as Record<string, string>

  if (provider !== "google") {
    res.status(400).json({ error: `Unsupported provider: ${provider}` })
    return
  }

  const clientId = client_id || process.env.GOOGLE_CLIENT_ID
  const clientSecret = client_secret || process.env.GOOGLE_CLIENT_SECRET

  if (!clientId || !clientSecret) {
    res.status(400).json({
      error:
        "Missing Google credentials. Set GOOGLE_CLIENT_ID / GOOGLE_CLIENT_SECRET " +
        "or pass client_id + client_secret as query params (BYOK mode).",
    })
    return
  }

  const codeVerifier = generateCodeVerifier()
  const codeChallenge = generateCodeChallenge(codeVerifier)
  const sessionId = generateSessionId()

  const baseUrl = `${req.protocol}://${req.get("host")}`
  const callbackRedirectUri = `${baseUrl}/~oauth/callback`

  sessions.set(sessionId, {
    codeVerifier,
    clientState: state || "",
    clientId,
    clientSecret,
    callbackRedirectUri,
    deliveryMode: (mode as "web_message" | "redirect"),
    originalRedirectUri: redirect_uri || "/",
    createdAt: Date.now(),
  })

  // We use sessionId as Google's `state` so we can look up the PKCE session
  // on the callback without exposing the original client state to Google.
  const googleParams = new URLSearchParams({
    client_id: clientId,
    redirect_uri: callbackRedirectUri,
    response_type: "code",
    scope: "openid email profile",
    state: sessionId,
    code_challenge: codeChallenge,
    code_challenge_method: "S256",
    access_type: "offline",
    prompt: "consent",
    ...extraParams,
  })

  res.redirect(`${GOOGLE_AUTH_URL}?${googleParams.toString()}`)
})

app.get("/~oauth/callback", async (req: Request, res: Response) => {
  const { code, state: sessionId, error } = req.query as Record<string, string>

  if (error) {
    res.status(400).send(errorPage(error))
    return
  }

  const session = sessions.get(sessionId)
  if (!session) {
    res.status(400).send(errorPage("Invalid or expired OAuth session."))
    return
  }

  // Consume session immediately to prevent replay attacks
  sessions.delete(sessionId)

  try {
    const tokenRes = await fetch(GOOGLE_TOKEN_URL, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        code,
        client_id: session.clientId,
        client_secret: session.clientSecret,
        redirect_uri: session.callbackRedirectUri,
        grant_type: "authorization_code",
        code_verifier: session.codeVerifier,
      }).toString(),
    })

    const tokenData = (await tokenRes.json()) as {
      access_token?: string
      refresh_token?: string
      error?: string
      error_description?: string
    }

    if (!tokenRes.ok || !tokenData.access_token) {
      throw new Error(
        tokenData.error_description ??
          tokenData.error ??
          "Token exchange failed"
      )
    }

    if (session.deliveryMode === "web_message") {
      res.send(webMessagePage(session.clientState, tokenData.access_token, tokenData.refresh_token ?? ""))
      return
    }

    // redirect mode — tokens in URL hash
    const hash = new URLSearchParams({
      access_token: tokenData.access_token,
      refresh_token: tokenData.refresh_token ?? "",
      state: session.clientState,
    }).toString()
    res.redirect(`${session.originalRedirectUri}#${hash}`)
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err)
    res.status(500).send(errorPage(message))
  }
})

// ─── HTML helpers ──────────────────────────────────────────────────────────────

function webMessagePage(
  state: string,
  access_token: string,
  refresh_token: string
): string {
  const payload = JSON.stringify({
    type: "authorization_response",
    response: { access_token, refresh_token, state },
  })

  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><title>Authenticating…</title></head>
<body>
<script>
(function () {
  var payload = ${payload};
  if (window.opener) {
    window.opener.postMessage(payload, '*');
    window.close();
  } else if (window.parent !== window) {
    window.parent.postMessage(payload, '*');
  }
})();
</script>
<p style="font-family:sans-serif">Authentication complete. You may close this window.</p>
</body>
</html>`
}

function errorPage(message: string): string {
  const safe = message.replace(/</g, "&lt;").replace(/>/g, "&gt;")
  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><title>OAuth Error</title></head>
<body>
<script>
(function () {
  var payload = {
    type: 'authorization_response',
    response: { error: ${JSON.stringify(safe)}, state: '' }
  };
  if (window.opener) { window.opener.postMessage(payload, '*'); window.close(); }
})();
</script>
<p style="font-family:sans-serif;color:#c00">OAuth error: ${safe}</p>
</body>
</html>`
}

// ─── Start ─────────────────────────────────────────────────────────────────────

const PORT = Number(process.env.PORT ?? 3001)
app.listen(PORT, () => {
  console.log(`OAuth broker listening on http://localhost:${PORT}`)
})

export default app
